@namespace CheckoutWizard.Components

<div class="checkout-wizard">
    @switch (_step)
    {
        case Step.Shipping:
            <ShippingStep Shipping="@_order.Shipping"
                          OnNext="@HandleShippingNext" />
            break;

        case Step.Payment:
            <PaymentStep Payment="@_order.Payment"
                         OnBack="@HandlePaymentBack"
                         OnPlaceOrder="@HandlePlaceOrder" />
            break;
    }
</div>

@code {
    private enum Step { Shipping, Payment }

    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private readonly Order _order = new();
    private Step _step = Step.Shipping;

    private void HandleShippingNext()
    {
        _step = Step.Payment;
    }

    private void HandlePaymentBack()
    {
        _step = Step.Shipping;
    }

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@namespace CheckoutWizard.Components
@implements IDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@_isValidating">
    <legend>Shipping Information</legend>

    <label>
        Name
        <input @bind="Shipping.Name" @bind:event="oninput" />
    </label>

    <label>
        Address
        <input @bind="Shipping.Address" @bind:event="oninput" />
    </label>

    <label>
        City
        <input @bind="Shipping.City" @bind:event="oninput" />
    </label>

    <label>
        Zip Code
        <input @bind="Shipping.ZipCode" @bind:event="oninput" />
    </label>
</fieldset>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <p class="validation-error">@_errorMessage</p>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        @:Validating…
    }
    else
    {
        @:Next
    }
</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _errorMessage;

    private async Task ValidateAndProceed()
    {
        _errorMessage = null;

        // Cancel any in-flight validation (e.g. user went back, changed fields, clicked Next again).
        CancelPendingValidation();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was intentionally cancelled — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

